#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Tree {
	int L , R , sum;
}; 
Tree tr[400005];
int t;
int n , m;
void build( int p , int L , int R ) {
	tr[p].L = L;
	tr[p].R = R;
	tr[p].sum = 1;
	if( L == R ) {
		return;
	}
	int mid = ( L + R ) / 2;
	build( p << 1 , L , mid );
	build( ( p << 1 ) + 1 , mid + 1 , R );
}
void modify( int p , int a , int b )  {
	if( tr[p].L > a || tr[p].R < a ) {
		return;
	}
	if( tr[p].L == a && tr[p].R == a ) {
		tr[p].sum = b;
		return;
	}
	modify( p << 1 ,  a , b );
	modify( ( p << 1 ) + 1 , a , b );
	tr[p].sum = tr[p << 1].sum * tr[( p << 1 ) + 1].sum % m;
}
int query( int p , int a , int b ) {
	if( tr[p].L > b || tr[p].R < a ) {
		return 0;
	}
	if( tr[p].L >= a && tr[p].R <= b ) {
		return tr[p].sum;
	}
	int sum = 1;
	sum *= query( p << 1 , a , b );
	sum *= query( ( p << 1 ) + 1 , a , b );
	return sum % m;
}
signed main() {
	cin >> t;
	while( t-- ) {
		cin >> n >> m;
		build( 1 , 1 , n );
		for( int i = 1 ; i <= n ; i++ ) {
			int op , x;
			cin >> op >> x;
			if( op == 1 ) {
				modify( 1 , i , x );
			} else {
				modify( 1 , x , 1 );
			}
			cout << query( 1 , 1 , n ) << '\n';
		}
	}
	return 0;
}
